let currentIndex = 0;

function useState(initialValue) {
  // 实现useState逻辑
  // 提示：
  // 1. 使用闭包保存状态
  // 2. 返回[state, setState]
  // 3. setState需要触发重渲染
}

// 重置Hook索引（每次渲染前调用）
function resetHookIndex() {
