questions.reference_solution:
let stateSlots = [];
let currentIndex = 0;
let currentComponent = null;

function useState(initialValue) {
  const slotIndex = currentIndex;

  // 初始化状态（只在首次渲染时）
  if (stateSlots[slotIndex] === undefined) {
    stateSlots[slotIndex] = typeof initialValue === 'function' 
      ? initialValue() 
      : initialValue;
  }

  const setState = (newValue) => {
    const prevValue = stateSlots[slotIndex];
    const nextValue = typeof newValue === 'function'
      ? newValue(prevValue)
      : newValue;

    // 只有值变化才触发重渲染
    if (!Object.is(prevValue, nextValue)) {
      stateSlots[slotIndex] = nextValue;
      // 触发重渲染
      if (currentComponent) {
        render(currentComponent);
      }
    }
  };

  currentIndex++;
  return [stateSlots[slotIndex], setState];
}

function resetHookIndex() {
  currentIndex = 0;
}

function render(Component) {
  currentComponent = Component;
  resetHookIndex();
  return Component();
}

