function useCallback(callback, deps) {
  // 实现useCallback
  // callback: 回调函数
  // deps: 依赖数组
}

// 依赖比较函数
function areDepsEqual(prevDeps, nextDeps) {
  // 实现依赖比较
}

questions.reference_solution:
let hookSlots = [];
let currentIndex = 0;

function useMemo(factory, deps) {
  const slotIndex = currentIndex;
  const slot = hookSlots[slotIndex];

  // 首次渲染或依赖变化
  if (
    !slot ||
    !areDepsEqual(slot.deps, deps)
  ) {
    hookSlots[slotIndex] = {
      value: factory(),
      deps: deps
    };
  }

  currentIndex++;
  return hookSlots[slotIndex].value;
}

function useCallback(callback, deps) {
  const slotIndex = currentIndex;
  const slot = hookSlots[slotIndex];

  // 首次渲染或依赖变化
  if (
    !slot ||
    !areDepsEqual(slot.deps, deps)
  ) {
    hookSlots[slotIndex] = {
      value: callback,
      deps: deps
    };
  }

  currentIndex++;
  return hookSlots[slotIndex].value;
}

function areDepsEqual(prevDeps, nextDeps) {
  // 处理undefined
  if (prevDeps === undefined || nextDeps === undefined) {
    return false;
  }

  if (prevDeps.length !== nextDeps.length) {
    return false;
  }

  for (let i = 0; i < prevDeps.length; i++) {
    if (!Object.is(prevDeps[i], nextDeps[i])) {
      return false;
    }
  }

  return true;
}

questions.explanation:
useCallback和useMemo是React最重要的性能优化Hook，理解其实现原理对于正确使用至关重要。

核心设计思想：

1. 依赖缓存：
useMemo和useCallback都基于依赖数组决定是否重新计算。依赖不变则返回缓存值，依赖变化则重新计算。

2. Hook存储结构：
每个Hook在hookSlots数组中有一个slot，存储value和deps。

useMemo实现细节：

// 使用示例
const expensiveValue = useMemo(() => {
  return computeExpensiveValue(a, b);
}, [a, b]);

// 等价于
let cachedValue;
if (depsChanged) {
  cachedValue = computeExpensiveValue(a, b);
}

useCallback实现细节：

// 使用示例
const memoizedCallback = useCallback(() => {
  doSomething(a, b);
}, [a, b]);

// 等价于
useMemo(() => () => {
  doSomething(a, b);
}, [a, b]);

useCallback本质上就是useMemo的特殊形式。

依赖比较原理：

React使用Object.is进行依赖比较：

Object.is(1, 1); // true
Object.is('a', 'a'); // true
Object.is({}, {}); // false（不同引用）
Object.is(NaN, NaN); // true（与===不同）

常见陷阱：

1. 对象作为依赖：
const obj = { a: 1 };
useEffect(() => {}, [obj]); // 每次都是新对象，依赖永远变化

// 解决：使用useMemo
const obj = useMemo(() => ({ a: 1 }), [a]);

2. 函数作为依赖：
const fn = () => {};
useEffect(() => {}, [fn]); // 每次都是新函数

// 解决：使用useCallback
const fn = useCallback(() => {}, [deps]);

3. 空依赖数组：
useMemo(() => value, []); // 只计算一次
useMemo(() => value); // 每次都计算（无依赖）

useMemo vs useCallback：

useMemo：缓存任意值
useCallback：缓存函数

// useCallback(fn, deps) 等价于
useMemo(() => fn, deps)

性能优化策略：

1. 缓存计算结果：
const sortedList = useMemo(() => {
  return [...list].sort(compareFn);
}, [list]);

2. 稳定回调引用：
const handleSubmit = useCallback((data) => {
  submit(data);
}, [submit]);

3. 配合React.memo：
const MemoChild = React.memo(Child);

function Parent() {
  const handleClick = useCallback(() => {}, []);
  return <MemoChild onClick={handleClick} />;
}

注意事项：

1. 不要过度优化：简单操作可能比useMemo开销更大
2. 依赖数组必须完整：ESLint插件帮助检测
3. useCallback不等于性能：内部实现有成本

questions.content:
以下是Vue 3响应式系统的track函数简化版本。请分析这个函数的作用和执行流程：

function track(target, type, key) {
  if (!shouldTrack || !activeEffect) return;

  let depsMap = targetMap.get(target);
  if (!depsMap) {
    targetMap.set(target, (depsMap = new Map()));
  }

  let dep = depsMap.get(key);
  if (!dep) {
    depsMap.set(key, (dep = createDep()));
  }

  trackEffects(dep);
}

questions.explanation:
track是Vue 3响应式系统依赖收集的核心函数，理解其工作原理对于掌握Vue至关重要。

track函数执行流程：

1. 前置检查：
if (!shouldTrack || !activeEffect) return;

shouldTrack：全局标志，控制是否收集依赖
activeEffect：当前正在执行的副作用函数

如果不在副作用执行期间或不需要追踪，直接返回。

2. 获取/创建depsMap：
let depsMap = targetMap.get(target);
if (!depsMap) {
  targetMap.set(target, (depsMap = new Map()));
}

targetMap是WeakMap<object, depsMap>
depsMap是Map<string, dep>

每个响应式对象对应一个depsMap。

3. 获取/创建dep：
let dep = depsMap.get(key);
if (!dep) {
  depsMap.set(key, (dep = createDep()));
}

dep是Set<ReactiveEffect>，存储所有依赖该属性的副作用。

4. 收集依赖：
trackEffects(dep);

function trackEffects(dep) {
  if (!dep.has(activeEffect)) {
    dep.add(activeEffect);
    activeEffect.deps.push(dep);
  }
}

建立双向引用：
- dep中存储activeEffect
- activeEffect.deps中也存储dep（便于清理）

完整流程示例：

const state = reactive({ count: 0 });

effect(() => {
  console.log(state.count);
});

执行过程：

1. effect(() => { ... })执行
   - activeEffect = 副作用函数

2. 副作用函数执行，访问state.count

3. Proxy的get trap触发

4. track(target, 'get', 'count')调用

5. 创建依赖结构：
   targetMap: {
     [state对象]: {
       'count': Set([副作用函数])
     }
   }

6. 后续state.count = 1时，trigger遍历Set执行副作用

type参数的作用：

track(target, TrackOpTypes.GET, key);

TrackOpTypes包括：
- GET：读取属性
- HAS：in操作符
- ITERATE：迭代（如for...in）

不同类型可能影响依赖收集的范围。

与trigger的配合：

function trigger(target, type, key) {
  const depsMap = targetMap.get(target);
  if (!depsMap) return;

  const dep = depsMap.get(key);
  if (dep) {
    triggerEffects(dep);
  }
}

track收集依赖，trigger触发依赖，形成完整的响应式循环。

性能优化：

1. WeakMap避免内存泄漏：
   target使用WeakMap，对象被GC时自动清理

2. 延迟创建：
   depsMap和dep按需创建，避免预分配

3. 双向引用：
   effect.deps用于快速清理所有依赖

shouldTrack的控制：

// 暂停追踪
pauseTracking();
shouldTrack = false;

// 恢复追踪
resetTracking();

用于数组变异方法内部，避免无限循环。

选项B错误原因：
trigger函数才是触发副作用执行的函数，track只负责收集依赖。

虚拟DOM是现代前端框架的核心抽象层，理解其设计理念对于掌握框架至关重要。

选项A解析 - JavaScript对象：
正确。虚拟DOM是纯JavaScript对象：

// React VNode
const reactElement = {
  type: 'div',
  props: {
    className: 'container',
    children: 'Hello'
  }
};

// Vue VNode
const vueVNode = {
  type: 'div',
  props: { class: 'container' },
  children: 'Hello',
  patchFlag: 0
};

这是框架能够跨平台的基础——虚拟DOM与平台无关。

选项B解析 - 批量更新和最小化操作：
正确。虚拟DOM的核心优势：

1. 批量更新：
// 多次setState
setState({ a: 1 });
setState({ b: 2 });
setState({ c: 3 });

// 虚拟DOM合并为一次更新
// 只触发一次重渲染

2. 最小化DOM操作：
// 旧树
<div><span>A</span></div>

// 新树
<div><span>B</span></div>

// Diff发现只有文本变化
// 只更新textContent，不重建DOM

选项C解析 - 性能误区：
错误。虚拟DOM不是万能的性能解决方案：

// 虚拟DOM的开销
1. 创建VNode对象
2. Diff算法执行
3. Patch DOM操作

// 直接DOM操作
1. 直接操作DOM

对于简单场景，直接DOM操作更快。虚拟DOM的优势在于复杂场景的批量更新和可维护性。

选项D解析 - 结构差异：
错误。React和Vue的虚拟DOM结构不同：

// React Element
{
  $$typeof: REACT_ELEMENT_TYPE,
  type: 'div',
  key: null,
  ref: null,
  props: { children: 'Hello' },
  _owner: null
}

// Vue VNode
{
  type: 'div',
  props: null,
  key: null,
  children: 'Hello',
  patchFlag: 0,
  dynamicChildren: null,
  shapeFlag: 8,
  // ...
}

Vue的VNode有额外的优化字段（patchFlag、dynamicChildren）。

选项E解析 - 跨平台支持：
正确。虚拟DOM是平台无关的抽象：

// Web
import { render } from 'react-dom';

// Native
import { render } from 'react-native';

// Canvas
import { render } from 'react-canvas';

// Terminal
import { render } from 'ink';

相同的组件代码，不同的渲染器，实现跨平台。

虚拟DOM的完整工作流程：

1. 创建：JSX/Template编译为VNode创建函数

// JSX
<div className="app">Hello</div>

// 编译为
React.createElement('div', { className: 'app' }, 'Hello')

2. Diff：比较新旧VNode树

function reconcile(oldVNode, newVNode) {
  // 比较type和key
  // 决定复用、更新或删除
}

3. Patch：将变化应用到真实DOM

function patchDOM(operations) {
  operations.forEach(op => {
    switch (op.type) {
      case 'INSERT': dom.appendChild(op.node); break;
      case 'UPDATE': updateProps(op.node, op.props); break;
      case 'DELETE': dom.removeChild(op.node); break;
    }
  });
}

虚拟DOM的局限：

1. 内存占用：需要维护完整的虚拟树
2. 首次渲染开销：创建VNode + 渲染
3. 不适合高性能动画：每帧都需要Diff

替代方案：

1. Svelte：编译时优化，无虚拟DOM
2. Solid.js：细粒度响应式，直接DOM更新
3. Preact：轻量虚拟DOM，更小的运行时

useSyncExternalStore是React 18为并发安全引入的重要Hook，解决了外部状态订阅的撕裂问题。

并发模式的问题：

在并发模式下，React可能在渲染过程中暂停并让出主线程。这导致一个潜在问题：

// 问题场景
function Component() {
  const value1 = externalStore.get(); // 渲染开始时读取
  // ... React暂停，让出主线程
  // 外部store被更新
  const value2 = externalStore.get(); // 渲染恢复时读取

  // value1和value2可能不同！
  // 导致UI不一致（Tearing）
}

useSyncExternalStore的解决方案：

const value = useSyncExternalStore(
  subscribe, // 订阅函数
  getSnapshot, // 获取快照
  getServerSnapshot? // SSR时的快照
);

// 内部实现概念
function useSyncExternalStore(subscribe, getSnapshot) {
  // 强制同步读取
  // 在并发渲染期间，如果store变化，强制同步更新

  // 关键：使用getSnapshot保证整个渲染过程中读取相同值
}

API详解：

1. subscribe：注册回调，store变化时调用
(subscribe) => {
  externalStore.subscribe(() => {
    // 触发React重渲染
    React.scheduleUpdate();
  });
}

2. getSnapshot：返回store的不可变快照
() => externalStore.getState()

3. getServerSnapshot：服务端渲染时使用
() => initialServerState

实际使用示例：

// 订阅Redux store
import { useSyncExternalStore } from 'react';

function useReduxStore(selector) {
  const store = useStore();

  return useSyncExternalStore(
    (callback) => store.subscribe(callback),
    () => selector(store.getState())
  );
}

// 订阅浏览器API
function useOnlineStatus() {
  return useSyncExternalStore(
    (callback) => {
      window.addEventListener('online', callback);
      window.addEventListener('offline', callback);
      return () => {
        window.removeEventListener('online', callback);
        window.removeEventListener('offline', callback);
      };
    },
    () => navigator.onLine
  );
}

Tearing问题详解：

Tearing是指渲染过程中状态不一致导致UI撕裂：

// 可能出现Tearing的代码
function ProductList() {
  const products = externalStore.products;

  return (
    <ul>
      {products.map(p => (
        // 如果渲染中途products变化
        // 前几个用旧数据，后几个用新数据
        <li key={p.id}>{p.name}</li>
      ))}
    </ul>
  );
}

useSyncExternalStore保证整个渲染过程中快照一致。

与并发模式的关系：

React 18的并发特性（useTransition、useDeferredValue）允许渲染被中断。useSyncExternalStore确保：

1. 渲染期间store快照一致
2. store变化时强制同步更新
3. 不会出现中间状态的UI

Redux/Zustand的适配：

现代状态管理库已内置支持：

// Zustand
const useStore = create((set) => ({ count: 0 }));

// 内部使用useSyncExternalStore
function useZustandStore(store, selector) {
  return useSyncExternalStore(
    store.subscribe,
    () => selector(store.getState())
  );
}

迁移指南：

// 旧代码（并发不安全）
useEffect(() => {
  const unsubscribe = store.subscribe(() => {
    setState(store.getState());
  });
  return unsubscribe;
}, []);

// 新代码（并发安全）
const state = useSyncExternalStore(
  store.subscribe,
  store.getState
);
